	(106050,'_transient_dash_88ae138922fe95674369b1cb3d215a2b','<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wordpress.org/news/2017/04/wordpress-4-7-4/\'>WordPress 4.7.4 Maintenance Release</a> <span class=\"rss-date\">April 20, 2017</span><div class=\"rssSummary\">After almost sixty million downloads of WordPress 4.7, we are pleased to announce the immediate availability of WordPress 4.7.4, a maintenance release. This release contains 47 bug fixes and enhancements, chief among them an incompatibility between the upcoming Chrome version and the visual editor, inconsistencies in media handling, and further improvements to the REST API.</div></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wptavern.com/how-the-san-francisco-wordpress-meetup-is-using-open-collective-to-fund-activities\'>WPTavern: How the San Francisco WordPress Meetup is Using Open Collective to Fund Activities</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/wordcamp-us-2017-ramps-up-ticket-sales-organizers-plan-for-2500-attendees\'>WPTavern: WordCamp US 2017 Ramps Up Ticket Sales, Organizers Plan for 2,500 Attendees</a></li><li><a class=\'rsswidget\' href=\'https://wptavern.com/watsonfinds-wordpress-plugin-uses-ibms-watson-to-determine-most-likely-emotional-response-from-readers\'>WPTavern: Watsonfinds WordPress Plugin Uses IBM’s Watson to Determine Most Likely Emotional Response From Readers</a></li></ul></div><div class=\"rss-widget\"><ul><li class=\"dashboard-news-plugin\"><span>Popular Plugin:</span> Yoast SEO&nbsp;<a href=\"plugin-install.php?tab=plugin-information&amp;plugin=wordpress-seo&amp;_wpnonce=29590188ae&amp;TB_iframe=true&amp;width=600&amp;height=800\" class=\"thickbox open-plugin-details-modal\" aria-label=\"Install Yoast SEO\">(Install)</a></li></ul></div>','no',0),
