	(14268,7,'_g_feedback_shortcode_atts','a:6:{s:2:\"to\";s:22:\"scott.c.taylor@mac.com\";s:7:\"subject\";s:25:\"[Goodbye Picasso] Contact\";s:12:\"show_subject\";s:2:\"no\";s:6:\"widget\";i:0;s:2:\"id\";i:7;s:18:\"submit_button_text\";s:13:\"Submit &#187;\";}'),
	(14527,2501,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:1177:\"<!doctype html>\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\n<body>\n\n<b>Name:</b> Ed Frez<br /><br /><b>Email:</b> edmundse816@gmail.com<br /><br /><b>Website:</b> <br /><br /><b>Message:</b> I want to see if we can schedule a call in regards to upgrading or changing your site to a more cutting edge look and feel and/or adding a few elements to the site that will help automate some of your business. Is this something you\'re interested in? We are experts in wordpress and various other website platforms / shopping carts (I\'d love to tell you more about these platforms if you\'re not familiar with them).  Do you have a few moments that we can talk in the next couple of days that would work for you? I can give you plenty of information and examples of what we\'ve done for other clients and other sites and what the results have been. Let me know if you\'re interested and hopefully we\'ll be able to speak soon. Thanks, Ed Frez - Web Designer / Programmer<br /><br /><br /><hr />Time: August 10, 2017 at 5:13 pm<br />IP Address: 206.123.95.137<br />Contact Form URL: https://goodbyepicasso.com/contact/<br /><p>Sent by an unverified visitor to your site.</p>\n\n</body>\n</html>\";}'),
