	(1668,821,'_feedback_all_fields','a:4:{s:4:\"Name\";s:10:\"Steve Shay\";s:5:\"Email\";s:24:\"steveinmilford@yahoo.com\";s:7:\"Website\";s:0:\"\";s:7:\"Message\";s:788:\"We drove down from Milford PA (about 2 hours) to hear Spirit Family Reunion (who we\'d heard up here at a Music Festival 2 years ago, and who were performing right after your set).  We got there early and were INCREDIBLY happy we did.  What a great sound -- we\'re glad we bought the CD last night too.  You guys are going to go VERY far -- it will be nice to see you break through to the big time someday (I\'m thinking sooner than later).  If you ever would consider doing a private party (maybe) up here in Milford PA, shoot me an email.  If not, I think you\'re definitely worth seeing again and again -- even if NYC is two hours away (it\'s still where I grew-up).\r\n\r\nPowerful performance, poetic excellence, and the crazy eyes are a perfect performance.  WOW!\r\n\r\nSteve Shay\r\n570-296-3730\";}'),
	(1669,821,'_feedback_extra_fields','a:0:{}'),
	(1671,821,'_feedback_email','a:4:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"subject\";s:25:\"[Goodbye Picasso] Contact\";s:7:\"message\";s:965:\"Name: Steve Shay\nEmail: steveinmilford@yahoo.com\nWebsite: \n\nWe drove down from Milford PA (about 2 hours) to hear Spirit Family Reunion (who we\'d heard up here at a Music Festival 2 years ago, and who were performing right after your set).  We got there early and were INCREDIBLY happy we did.  What a great sound -- we\'re glad we bought the CD last night too.  You guys are going to go VERY far -- it will be nice to see you break through to the big time someday (I\'m thinking sooner than later).  If you ever would consider doing a private party (maybe) up here in Milford PA, shoot me an email.  If not, I think you\'re definitely worth seeing again and again -- even if NYC is two hours away (it\'s still where I grew-up).\r\n\r\nPowerful performance, poetic excellence, and the crazy eyes are a perfect performance.  WOW!\r\n\r\nSteve Shay\r\n570-296-3730\n\n\nTime: Sunday February 13, 2011 at 11:59 pm\nIP Address: 24.102.170.178\n\nSent by an unverified visitor to your site.\";s:7:\"headers\";s:121:\"From: Steve Shay <steveinmilford@yahoo.com>\nReply-To: steveinmilford@yahoo.com\nContent-Type: text/plain; charset=\"UTF-8\"\n\";}'),
