	(14529,2502,'_feedback_akismet_values','a:23:{s:14:\"comment_author\";s:13:\"Tracy Edmunds\";s:20:\"comment_author_email\";s:25:\"traceyedmunds57@gmail.com\";s:18:\"comment_author_url\";s:8:\"http://~\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:14:\"107.172.44.252\";s:15:\"comment_content\";s:555:\"I\'m contacting you to see if we can setup a time to speak about your website.  I am a designer who can make websites really shine.  Consumers make a lot of judgement\'s about your company based on your site, which is why I feel that it\'s incredibly important (especially now) to make it look amazing.  Would you be willing to setup a 15 minute call with me where I can give you all of the ins and outs of what I could do and how I believe it would help your company?  I would really appreciate the opportunity to work with you.  \r\nSincerely,\r\nTracy Edmunds\";s:26:\"contact_form_field_website\";s:1:\"~\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:14:\"107.172.44.252\";s:10:\"user_agent\";s:104:\"Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/36.0.2028.65 Safari/537.36\";s:8:\"referrer\";s:35:\"https://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:14:\"107.172.44.252\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:20:\"HTTP_ACCEPT_ENCODING\";s:4:\"gzip\";s:19:\"HTTP_ACCEPT_CHARSET\";s:32:\"utf-8,windows-1251;q=0.7,*;q=0.7\";s:20:\"HTTP_ACCEPT_LANGUAGE\";s:14:\"en-us,en;q=0.6\";s:15:\"HTTP_KEEP_ALIVE\";s:3:\"300\";s:11:\"HTTP_ACCEPT\";s:99:\"text/xml,application/xml,application/xhtml+xml,text/html;q=0.9,text/plain;q=0.8,image/png,*/*;q=0.2\";s:19:\"HTTP_CONTENT_LENGTH\";s:3:\"710\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";}'),
