	(14539,2505,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:967:\"<!doctype html>\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\n<body>\n\n<b>Name:</b> Your video<br /><br /><b>Email:</b> steveward-fanyzqt@gmail.com<br /><br /><b>Website:</b> http://accurate-media-solutions.info<br /><br /><b>Message:</b> Hey Steve here.. Just a quick question for you..<br />\r\n what number of new sales do you think you will gain if you had a lead capture video on the front page of google for EVERY product and service that you offer and showing in EVERY local google search made for the city and towns that you cover..<br />\r\n sounds to to far fetched to be true? Check out my proof and case study thank-you Steve <br />\r\n p.s  <br />\r\n results follow in days not months like seo. <br />\r\n http://bit.ly/Video-Domination-Marketing<br /><br /><br /><hr />Time: August 16, 2017 at 6:37 am<br />IP Address: 38.131.138.140<br />Contact Form URL: https://goodbyepicasso.com/contact/<br /><p>Sent by an unverified visitor to your site.</p>\n\n</body>\n</html>\";}'),
