	(14523,2500,'_feedback_akismet_values','a:20:{s:14:\"comment_author\";s:41:\"Would you like your business to be on tv?\";s:20:\"comment_author_email\";s:36:\"sal-ward@accuratemediasolutions.info\";s:18:\"comment_author_url\";s:34:\"http://accuratemediasolutions.info\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:15:\"104.144.140.107\";s:15:\"comment_content\";s:1005:\"Hi there! \r\n I honestly can\'t think of any business that wouldn\'t want their business in a tv commercial.\r\n However its really expensive and so untargeted! How many sales or customers do you think you will gain if you had a commercial running when they were looking for your business? \r\n My name is Sal and I am looking to work with a few businesses for an online commercial. Instead of being on TV, I want to put your business front and center with a video billboard (commercial) on Google & Youtube in your local area. Not just 1. Not just 5. Not just 10. \r\n But a complete domination of your local market with as many video billboard commercials that it takes to dominate your area. \r\n How many new customers will you get if they search for your service or product and all they see are billboards showcasing you? \r\n I have a few spots open. To see proof of results and what it can do for you please go to http://accuratemediasolutions.info to see some sample results and how we can do the same for you.\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:15:\"104.144.140.107\";s:10:\"user_agent\";s:61:\"Mozilla/5.0 (Windows NT 6.1; Trident/7.0; rv:11.0) like Gecko\";s:8:\"referrer\";s:34:\"http://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:15:\"104.144.140.107\";s:11:\"HTTP_ACCEPT\";s:87:\"image/gif, image/x-xbitmap, image/jpeg, image/pjpeg, application/x-shockwave-flash, */*\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:19:\"HTTP_CONTENT_LENGTH\";s:4:\"1261\";s:20:\"HTTP_ACCEPT_ENCODING\";s:13:\"gzip, deflate\";s:15:\"HTTP_CONNECTION\";s:5:\"Close\";}'),
	(14194,2385,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:664:\"<b>Name:</b> calsen<br /><br />\n<b>Email:</b> ellieyez@gmail.com<br /><br />\n<b>Website:</b> <br /><br />\n<b>Message:</b> hello! i bought your album about nine months ago, and it is very close to my  heart. i don\'t know much about your band but The Book Of Aylene really changed me. \"Her Name Is Aylene\"  and \"Notes and Measures\" are very touching, and i was wondering if you could post the chords somewhere? if not, that\'s okay too.  thanks for writing this amazing album!<br /><br />\n\nTime: December 21, 2016 at 8:52 pm<br />\nIP Address: 63.131.170.111<br />\nContact Form URL: https://goodbyepicasso.com/contact/<br />\nSent by an unverified visitor to your site.\";}');
