	(14535,2504,'_feedback_akismet_values','a:23:{s:14:\"comment_author\";s:15:\"Mckelvey Palmer\";s:20:\"comment_author_email\";s:27:\"palmermckelvey687@gmail.com\";s:18:\"comment_author_url\";s:10:\"http://n/a\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:13:\"104.144.83.41\";s:15:\"comment_content\";s:438:\"I love how your site looks, but I have a vision for it that would make me love it even more, and I\'m pretty sure that you would love it too. \r\n\r\nI am a professional web designer that can do amazing things and help sites reach their full potential. I also thought that the site may need additional features as well. I have some cool thoughts I want to share with you.  Can we set up a call? I\'d really love to talk to you soon.\r\n- Mckelvey\";s:26:\"contact_form_field_website\";s:3:\"n/a\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:13:\"104.144.83.41\";s:10:\"user_agent\";s:109:\"Mozilla/5.0 (Windows NT 10.0; WOW64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/44.0.2424.83 Safari/537.36\";s:8:\"referrer\";s:35:\"https://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:13:\"104.144.83.41\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:20:\"HTTP_ACCEPT_ENCODING\";s:4:\"gzip\";s:19:\"HTTP_ACCEPT_CHARSET\";s:32:\"utf-8,windows-1251;q=0.7,*;q=0.7\";s:20:\"HTTP_ACCEPT_LANGUAGE\";s:14:\"en-us,en;q=0.9\";s:15:\"HTTP_KEEP_ALIVE\";s:3:\"300\";s:11:\"HTTP_ACCEPT\";s:99:\"text/xml,application/xml,application/xhtml+xml,text/html;q=0.9,text/plain;q=0.8,image/png,*/*;q=0.3\";s:19:\"HTTP_CONTENT_LENGTH\";s:3:\"597\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";}'),
