	(14544,2507,'_feedback_akismet_values','a:20:{s:14:\"comment_author\";s:10:\"Your video\";s:20:\"comment_author_email\";s:28:\"stevechild-kvffgqz@gmail.com\";s:18:\"comment_author_url\";s:40:\"http://bit.ly/Video-Domination-Marketing\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:15:\"181.214.169.143\";s:15:\"comment_content\";s:1005:\"Hi there! \r\n I honestly can\'t think of any business that wouldn\'t want their business in a tv commercial.\r\n However its really expensive and so untargeted! How many sales or customers do you think you will gain if you had a commercial running when they were looking for your business? \r\n My name is Sal and I am looking to work with a few businesses for an online commercial. Instead of being on TV, I want to put your business front and center with a video billboard (commercial) on Google & Youtube in your local area. Not just 1. Not just 5. Not just 10. \r\n But a complete domination of your local market with as many video billboard commercials that it takes to dominate your area. \r\n How many new customers will you get if they search for your service or product and all they see are billboards showcasing you? \r\n I have a few spots open. To see proof of results and what it can do for you please go to http://accuratemediasolutions.info to see some sample results and how we can do the same for you.\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:15:\"181.214.169.143\";s:10:\"user_agent\";s:61:\"Mozilla/5.0 (Windows NT 6.1; Trident/7.0; rv:11.0) like Gecko\";s:8:\"referrer\";s:34:\"http://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:15:\"181.214.169.143\";s:11:\"HTTP_ACCEPT\";s:87:\"image/gif, image/x-xbitmap, image/jpeg, image/pjpeg, application/x-shockwave-flash, */*\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:19:\"HTTP_CONTENT_LENGTH\";s:4:\"1228\";s:20:\"HTTP_ACCEPT_ENCODING\";s:13:\"gzip, deflate\";s:15:\"HTTP_CONNECTION\";s:5:\"Close\";}'),
	(13834,2264,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:1612:\"<b>Name:</b> Garett Eddins<br /><br /><b>Email:</b> expertdesign78@gmail.com<br /><br /><b>Website:</b> http://n/a<br /><br /><b>Message:</b> Hi my name is Garett and I am part of an established web design agency. My team and I specialize in helping our client\'s businesses run easier with our fully managed web solutions. <br />\r\n<br />\r\nI notice that most business owners are still trying to get up to speed on all the changes that have happened with digital marketing and web development. This is understandable as running a business takes most of your time and energy.  <br />\r\n<br />\r\nIf you are looking to stand out from your competitors and are interested in how your site can help you do that, I would be happy to have a call and show you some of the ways have helped our client\'s sites accomplish this. <br />\r\n<br />\r\nThis consultation is of course free and there is no obligation to use our services. I will be happy to answer all your questions and also show you some ideas I have for your site as well. <br />\r\n<br />\r\nJust let me know what time works for you to have this call.<br />\r\n<br />\r\nThank you,<br />\r\n<br />\r\nGarett Eddins<br />\r\n<br />\r\nI offer this free consultation to give you the opportunity to see what we can do for you and also so you can see if we could be a good fit to work together. If you are not interested or would like to be removed from my list just let me know and I will remove you. Thanks.<br /><br />Time: March 27, 2016 at 8:56 pm<br />IP Address: 45.61.46.44<br />Contact Form URL: http://goodbyepicasso.com/contact/<br />Sent by an unverified visitor to your site.\";}'),
	(14537,2505,'_feedback_extra_fields','a:0:{}'),
	(14538,2505,'_feedback_akismet_values','a:20:{s:14:\"comment_author\";s:10:\"Your video\";s:20:\"comment_author_email\";s:27:\"steveward-fanyzqt@gmail.com\";s:18:\"comment_author_url\";s:36:\"http://accurate-media-solutions.info\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:14:\"38.131.138.140\";s:15:\"comment_content\";s:481:\"Hey Steve here.. Just a quick question for you..\r\n what number of new sales do you think you will gain if you had a lead capture video on the front page of google for EVERY product and service that you offer and showing in EVERY local google search made for the city and towns that you cover..\r\n sounds to to far fetched to be true? Check out my proof and case study thank-you Steve \r\n p.s  \r\n results follow in days not months like seo. \r\n http://bit.ly/Video-Domination-Marketing\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:14:\"38.131.138.140\";s:10:\"user_agent\";s:61:\"Mozilla/5.0 (Windows NT 6.1; Trident/7.0; rv:11.0) like Gecko\";s:8:\"referrer\";s:34:\"http://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:14:\"38.131.138.140\";s:11:\"HTTP_ACCEPT\";s:87:\"image/gif, image/x-xbitmap, image/jpeg, image/pjpeg, application/x-shockwave-flash, */*\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:19:\"HTTP_CONTENT_LENGTH\";s:3:\"685\";s:20:\"HTTP_ACCEPT_ENCODING\";s:13:\"gzip, deflate\";s:15:\"HTTP_CONNECTION\";s:5:\"Close\";}'),
	(14519,2499,'_feedback_extra_fields','a:0:{}'),
	(14520,2499,'_feedback_akismet_values','a:23:{s:14:\"comment_author\";s:12:\"Linton Brown\";s:20:\"comment_author_email\";s:27:\"songerguerrette85@gmail.com\";s:18:\"comment_author_url\";s:10:\"http://n/a\";s:20:\"contact_form_subject\";s:25:\"[Goodbye Picasso] Contact\";s:17:\"comment_author_IP\";s:12:\"198.12.72.56\";s:15:\"comment_content\";s:426:\"Are you at the front of the pack in the search engines, or are you buried in the middle where no one can find you?  If you\'re buried on page 2 or beyond, then you\'re missing out on a TON of profits and we really need to talk.  I provide very affordable optimization services that will bring your site to the forefront and increase your profits dramatically.  Interested?  Reply back and let me know what you think.  \r\n- Linton\";s:26:\"contact_form_field_website\";s:3:\"n/a\";s:12:\"comment_type\";s:12:\"contact_form\";s:7:\"user_ip\";s:12:\"198.12.72.56\";s:10:\"user_agent\";s:74:\"Mozilla/5.0 (X11; Ubuntu; Linux i686; rv:40.0) Gecko/20100101 Firefox/40.0\";s:8:\"referrer\";s:35:\"https://goodbyepicasso.com/contact/\";s:4:\"blog\";s:26:\"https://goodbyepicasso.com\";s:11:\"REQUEST_URI\";s:9:\"/contact/\";s:12:\"DOCUMENT_URI\";s:10:\"/index.php\";s:11:\"REMOTE_ADDR\";s:12:\"198.12.72.56\";s:9:\"HTTP_HOST\";s:18:\"goodbyepicasso.com\";s:20:\"HTTP_ACCEPT_ENCODING\";s:4:\"gzip\";s:19:\"HTTP_ACCEPT_CHARSET\";s:32:\"utf-8,windows-1251;q=0.7,*;q=0.5\";s:20:\"HTTP_ACCEPT_LANGUAGE\";s:14:\"en-us,en;q=0.7\";s:15:\"HTTP_KEEP_ALIVE\";s:3:\"300\";s:11:\"HTTP_ACCEPT\";s:99:\"text/xml,application/xml,application/xhtml+xml,text/html;q=0.9,text/plain;q=0.8,image/png,*/*;q=0.5\";s:19:\"HTTP_CONTENT_LENGTH\";s:3:\"576\";s:17:\"HTTP_CONTENT_TYPE\";s:33:\"application/x-www-form-urlencoded\";}'),
