	(13918,2292,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:681:\"<b>Name:</b> Anna Wyrwik<br /><br />\n<b>Email:</b> anna.wyrwik@gmail.com<br /><br />\n<b>Website:</b> <br /><br />\n<b>Message:</b> Hi,<br />\r\n<br />\r\nI was on your concert in Rockwood Music Hall. It was a time with piece of good music and a great culmination of my one month in US. Is it possible to buy your CD or maybe download it? I found your music only on YT and on your webside, but I\'m looking for audio  in better quality.<br />\r\n<br />\r\nThank you for concert and all the best!<br />\r\nAnia<br /><br />\n\nTime: May 27, 2016 at 8:07 am<br />\nIP Address: 159.205.207.93<br />\nContact Form URL: http://goodbyepicasso.com/contact/<br />\nSent by an unverified visitor to your site.\";}'),
	(14545,2507,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:1508:\"<!doctype html>\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\n<body>\n\n<b>Name:</b> Your video<br /><br /><b>Email:</b> stevechild-kvffgqz@gmail.com<br /><br /><b>Website:</b> http://bit.ly/Video-Domination-Marketing<br /><br /><b>Message:</b> Hi there! <br />\r\n I honestly can\'t think of any business that wouldn\'t want their business in a tv commercial.<br />\r\n However its really expensive and so untargeted! How many sales or customers do you think you will gain if you had a commercial running when they were looking for your business? <br />\r\n My name is Sal and I am looking to work with a few businesses for an online commercial. Instead of being on TV, I want to put your business front and center with a video billboard (commercial) on Google &amp; Youtube in your local area. Not just 1. Not just 5. Not just 10. <br />\r\n But a complete domination of your local market with as many video billboard commercials that it takes to dominate your area. <br />\r\n How many new customers will you get if they search for your service or product and all they see are billboards showcasing you? <br />\r\n I have a few spots open. To see proof of results and what it can do for you please go to http://accuratemediasolutions.info to see some sample results and how we can do the same for you.<br /><br /><br /><hr />Time: August 17, 2017 at 12:28 am<br />IP Address: 181.214.169.143<br />Contact Form URL: https://goodbyepicasso.com/contact/<br /><p>Sent by an unverified visitor to your site.</p>\n\n</body>\n</html>\";}'),
	(13798,2252,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:321:\"<b>Name:</b> Keech<br /><br /><b>Email:</b> atkeech@gmail.com<br /><br /><b>Website:</b> <br /><br /><b>Message:</b> Any upcoming shows?<br /><br />Time: February 20, 2016 at 1:13 pm<br />IP Address: 24.102.112.173<br />Contact Form URL: http://goodbyepicasso.com/contact/<br />Sent by an unverified visitor to your site.\";}'),
