	(13741,2232,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:227:\"Name: Jon Anderson\nEmail: 231designz@gmail.com\nWebsite: \nMessage: \n\nTime: December 21, 2015 at 3:52 am\nIP Address: 107.173.223.158\nContact Form URL: http://goodbyepicasso.com/contact/\nSent by an unverified visitor to your site.\";}'),
	(13739,2232,'_feedback_extra_fields','a:0:{}'),
	(14530,2502,'_feedback_email','a:2:{s:2:\"to\";a:1:{i:0;s:22:\"scott.c.taylor@mac.com\";}s:7:\"message\";s:997:\"<!doctype html>\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\n<body>\n\n<b>Name:</b> Tracy Edmunds<br /><br /><b>Email:</b> traceyedmunds57@gmail.com<br /><br /><b>Website:</b> http://~<br /><br /><b>Message:</b> I\'m contacting you to see if we can setup a time to speak about your website.  I am a designer who can make websites really shine.  Consumers make a lot of judgement\'s about your company based on your site, which is why I feel that it\'s incredibly important (especially now) to make it look amazing.  Would you be willing to setup a 15 minute call with me where I can give you all of the ins and outs of what I could do and how I believe it would help your company?  I would really appreciate the opportunity to work with you.  <br />\r\nSincerely,<br />\r\nTracy Edmunds<br /><br /><br /><hr />Time: August 11, 2017 at 12:59 pm<br />IP Address: 107.172.44.252<br />Contact Form URL: https://goodbyepicasso.com/contact/<br /><p>Sent by an unverified visitor to your site.</p>\n\n</body>\n</html>\";}'),
